WITH expected_rpc AS (SELECT * FROM (VALUES ('admin_deactivate_profiles_v1','public.admin_deactivate_profiles_v1(uuid[],text)'), ('admin_restore_profiles_v1','public.admin_restore_profiles_v1(uuid[],text)'), ('admin_list_deactivated_profiles_v1','public.admin_list_deactivated_profiles_v1()')) AS v(item_name, signature)), rpc_rows AS (SELECT 10 AS sort_key, 'rpc_access'::text AS audit_section, e.item_name::text, CASE WHEN to_regprocedure(e.signature) IS NULL THEN 'missing' ELSE has_function_privilege('anon', to_regprocedure(e.signature), 'EXECUTE')::text END AS detail_1, CASE WHEN to_regprocedure(e.signature) IS NULL THEN 'missing' ELSE has_function_privilege('authenticated', to_regprocedure(e.signature), 'EXECUTE')::text END AS detail_2 FROM expected_rpc e), guard_rows AS (SELECT 20 AS sort_key, 'backend_guard'::text AS audit_section, 'trg_profiles_guard_account_lifecycle_v1'::text AS item_name, CASE WHEN EXISTS (SELECT 1 FROM information_schema.triggers WHERE event_object_schema = 'public' AND event_object_table = 'profiles' AND trigger_name = 'trg_profiles_guard_account_lifecycle_v1') THEN 'present' ELSE 'missing' END::text AS detail_1, COALESCE(to_regprocedure('public.profiles_guard_account_lifecycle_v1()')::text, 'missing') AS detail_2 UNION ALL SELECT 21, 'backend_guard', 'profile_account_action_audit', COALESCE(to_regclass('public.profile_account_action_audit')::text, 'missing'), '<none>'), summary_rows AS (SELECT 30 AS sort_key, 'profiles_summary'::text AS audit_section, 'counts'::text AS item_name, ((count(*) FILTER (WHERE deleted_at IS NULL))::text || ' visible / ' || (count(*) FILTER (WHERE deleted_at IS NOT NULL))::text || ' deactivated')::text AS detail_1, ((count(*) FILTER (WHERE deleted_at IS NULL AND COALESCE(is_active,false) AND COALESCE(is_approved,false)))::text || ' approved_active')::text AS detail_2 FROM public.profiles) SELECT audit_section, item_name, detail_1, detail_2 FROM (SELECT * FROM rpc_rows UNION ALL SELECT * FROM guard_rows UNION ALL SELECT * FROM summary_rows) audit ORDER BY sort_key, item_name;
